const startRaw = (() => {
  try {
    return $('Start').first().json || {};
  } catch (e) {
    return $input.first()?.json || {};
  }
})();

/*
  Aceita 3 formatos de entrada no subworkflow:

  1. Linha direta da bruna_memoria_leads:
     {
       id,
       phone,
       account_id_chatwoot,
       conversation_id_chatwoot,
       ...
     }

  2. Linha embrulhada:
     {
       memory_row: {...}
     }

  3. Webhook manual do Chatwoot:
     {
       body: {...}
     }
*/

const input =
  startRaw.memory_row ||
  startRaw.lead_memory ||
  startRaw.row ||
  startRaw.payload_base ||
  startRaw;

const isWebhook = !!input.body;
const isMemoryRow =
  !isWebhook &&
  !!input.phone &&
  !!input.conversation_id_chatwoot;

function clean(value) {
  if (value === undefined || value === null) return '';
  return String(value)
    .replace(/[\u200B-\u200D\u2060\uFEFF]/g, ' ')
    .replace(/\uFFFD/g, ' ')
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n')
    .trim();
}

function onlyDigits(value) {
  return clean(value).replace(/\D/g, '');
}

function toBool(value, fallback = false) {
  if (value === true) return true;
  if (value === false) return false;
  if (value === 1 || value === '1') return true;
  if (value === 0 || value === '0') return false;

  const v = clean(value).toLowerCase();

  if (['true', 'sim', 'yes', 'y'].includes(v)) return true;
  if (['false', 'nao', 'não', 'no', 'n'].includes(v)) return false;

  return fallback;
}

function parseJsonMaybe(value, fallback = null) {
  if (value === undefined || value === null || value === '') return fallback;
  if (typeof value === 'object') return value;

  try {
    return JSON.parse(value);
  } catch (e) {
    return fallback;
  }
}

function normalizeStatus(value) {
  const v = clean(value);

  const valid = [
    'NOVO_LEAD',
    'COLETANDO_DADOS',
    'QUALIFICANDO',
    'PRE_REPROVADO',
    'APTO_PARA_AVALIACAO',
    'AGUARDANDO_PAGAMENTO',
    'COMPROVANTE_RECEBIDO',
    'AGUARDANDO_ESCOLHA_HORARIO',
    'PRE_RESERVA_CRIADA',
    'TRANSFERIDO_FLAVIA',
    'ENCERRADO_NAO_PERFIL',
    'ENCERRADO_SEM_RESPOSTA',
    'ENCERRADO'
  ];

  return valid.includes(v) ? v : 'QUALIFICANDO';
}

function normalizeIntent(value) {
  const v = clean(value);

  const valid = [
    'INTERESSE_CRECHE',
    'INTERESSE_HOTEL',
    'PEDIU_VALOR',
    'PEDIU_LOCALIZACAO',
    'PEDIU_VISITA',
    'INFORMOU_DADOS_CAO',
    'INFORMOU_DADOS_TUTOR',
    'ACEITOU_AVALIACAO',
    'RECEBEU_PIX',
    'ENVIOU_COMPROVANTE',
    'ESCOLHEU_HORARIO',
    'PEDIU_HUMANO',
    'MACHO_NAO_CASTRADO',
    'RACA_POTENCIAL_DANO',
    'URGENCIA_FERIADO',
    'OBJECAO_PRECO',
    'SUMIU'
  ];

  return valid.includes(v) ? v : 'SUMIU';
}

function normalizeEvent(value) {
  const v = clean(value);

  const valid = [
    '',
    'FORMULARIO_RECEBIDO',
    'GUIA_ENVIADO',
    'PIX_SOLICITADO',
    'ANEXO_RECEBIDO',
    'COMPROVANTE_IDENTIFICADO',
    'AGENDA_CONSULTADA',
    'HORARIOS_ENVIADOS',
    'PRE_RESERVA_CRIADA',
    'REPASSE_FLAVIA',
    'FOLLOWUP_DISPARADO',
    'CONVERSA_ENCERRADA'
  ];

  return valid.includes(v) ? v : '';
}

function normalizeNaoInformado(value) {
  const v = clean(value);
  return v || 'nao_informado';
}

function normalizeNaoDefinido(value) {
  const v = clean(value);
  return v || 'nao_definido';
}

function parseLeadSummary(text) {
  const raw = clean(text);
  const out = {};

  if (!raw) return out;

  const getLine = (label) => {
    const escaped = label.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    const regex = new RegExp(`${escaped}:\\s*([^\\n]+)`, 'i');
    const match = raw.match(regex);
    return match ? clean(match[1]) : '';
  };

  out.tutor_nome = getLine('Tutor');
  out.tutor_telefone = getLine('Telefone');

  out.status_lead = getLine('Status');
  out.ultima_intencao = getLine('Intenção');

  out.cao_nome = getLine('Nome do cão');
  out.cao_idade_anos = getLine('Idade');
  out.cao_raca = getLine('Raça');
  out.cao_porte = getLine('Porte');
  out.cao_sexo = getLine('Sexo');
  out.cao_castrado = getLine('Castrado');
  out.cao_vacinas_ok = getLine('Vacinas');
  out.cao_antipulgas_ok = getLine('Antipulgas');
  out.cao_sociavel = getLine('Sociável');
  out.cao_reativo = getLine('Reativo');

  out.servico_interesse = getLine('Serviço');
  out.unidade_preferida = getLine('Unidade');
  out.tipo_comprovante = getLine('Tipo comprovante');

  const comprovanteLinha = getLine('Comprovante recebido').toLowerCase();

  out.comprovante_recebido =
    comprovanteLinha.includes('sim') ||
    comprovanteLinha === 'true';

  const prox = raw.match(/Próxima ação:\s*([\s\S]*?)(?:\nObservações:|\n?$)/i);
  out.proxima_acao = prox ? clean(prox[1]) : '';

  const obs = raw.match(/Observações:\s*([\s\S]*)$/i);
  out.observacoes = obs ? clean(obs[1]) : '';

  return out;
}

/* ============================================================
   CAMINHO 1: WEBHOOK MANUAL CHATWOOT
   ============================================================ */

if (isWebhook) {
  const body = input.body || {};
  const msg0 = Array.isArray(body.messages) ? (body.messages[0] || {}) : {};
  const sender = body.meta?.sender || {};
  const custom = sender.custom_attributes || {};
  const contactInbox = body.contact_inbox || {};
  const attachments = Array.isArray(msg0.attachments) ? msg0.attachments : [];
  const firstAttachment = attachments[0] || null;

  const leadSummaryParsed = parseLeadSummary(custom.lead_summary || '');

  const accountId = Number(msg0.account_id || body.account_id || 0);
  const inboxId = Number(body.inbox_id || msg0.inbox_id || contactInbox.inbox_id || 0);
  const conversationId = Number(body.id || msg0.conversation_id || 0);
  const contactId = Number(sender.id || contactInbox.contact_id || 0);
  const messageId = Number(msg0.id || 0);

  const phone = clean(sender.phone_number || leadSummaryParsed.tutor_telefone || '');
  const leadName = clean(sender.name || leadSummaryParsed.tutor_nome || '');

  const labels = Array.isArray(body.labels)
    ? body.labels.map(x => clean(x)).filter(Boolean)
    : [];

  const messageText = clean(
    msg0.content ||
    msg0.processed_message_content ||
    ''
  );

  const hasAttachment = attachments.length > 0;
  const hasText = !!messageText;

  const messageType =
    Number(msg0.message_type) === 0
      ? 'incoming'
      : Number(msg0.message_type) === 1
        ? 'outgoing'
        : clean(msg0.sender_type).toLowerCase() === 'contact'
          ? 'incoming'
          : 'outgoing';

  const messageModality = hasAttachment
    ? `${clean(firstAttachment?.file_type || 'attachment')}_${hasText ? 'with_text' : 'only'}`
    : 'text_only';

  const statusLead = normalizeStatus(
    custom.bruna_status_lead ||
    leadSummaryParsed.status_lead ||
    ''
  );

  const ultimaIntencao = normalizeIntent(
    custom.bruna_ultima_intencao ||
    leadSummaryParsed.ultima_intencao ||
    ''
  );

  const eventoSistema = normalizeEvent(
    custom.bruna_evento_sistema ||
    ''
  );

  const servicoInteresse =
    clean(custom.bruna_servico_interesse) ||
    leadSummaryParsed.servico_interesse ||
    (
      ultimaIntencao === 'INTERESSE_HOTEL'
        ? 'hotel'
        : ultimaIntencao === 'INTERESSE_CRECHE'
          ? 'creche'
          : 'nao_definido'
    );

  const resumoLead = {
    tutor_nome: leadSummaryParsed.tutor_nome || leadName || '',
    tutor_telefone: leadSummaryParsed.tutor_telefone || phone || '',

    cao_nome: clean(custom.bruna_nome_cao) || leadSummaryParsed.cao_nome || '',
    cao_idade_anos: leadSummaryParsed.cao_idade_anos || '',
    cao_idade_texto: leadSummaryParsed.cao_idade_anos || '',
    cao_raca: clean(custom.bruna_raca_cao) || leadSummaryParsed.cao_raca || '',
    cao_porte: clean(custom.bruna_porte_cao) || leadSummaryParsed.cao_porte || 'nao_definido',
    cao_sexo: clean(custom.bruna_sexo_cao) || leadSummaryParsed.cao_sexo || 'nao_informado',
    cao_castrado: clean(custom.bruna_castrado) || leadSummaryParsed.cao_castrado || 'nao_informado',
    cao_no_cio: 'nao_informado',

    cao_vacinas_ok: leadSummaryParsed.cao_vacinas_ok || 'nao_informado',
    cao_antipulgas_ok: leadSummaryParsed.cao_antipulgas_ok || 'nao_informado',
    cao_vermifugacao_ok: 'nao_informado',
    cao_sociavel: leadSummaryParsed.cao_sociavel || 'nao_informado',
    cao_reativo: leadSummaryParsed.cao_reativo || 'nao_informado',
    possui_relatorio_veterinario: 'nao_informado',

    unidade_preferida: leadSummaryParsed.unidade_preferida || 'nao_definida',
    servico_interesse: servicoInteresse || 'nao_definido',
    periodo_desejado: '',
    data_desejada: '',
    data_checkin_desejada: '',
    data_checkout_desejada: '',

    origem_lead: clean(custom.origem || ''),
    origem_detalhada: clean(custom.origem || ''),
    comprovante_recebido: toBool(
      custom.bruna_comprovante_recebido,
      leadSummaryParsed.comprovante_recebido || false
    ),
    tipo_comprovante: leadSummaryParsed.tipo_comprovante || 'nao_informado',
    arquivo_comprovante_referencia: '',
    data_hora_avaliacao: '',
    data_hora_pre_reserva: '',
    pre_reserva_criada: false,
    responsavel_humano: '',
    observacoes: leadSummaryParsed.observacoes || ''
  };

  const resumoInternoRepasse = {
    repassar_para: '',
    motivo: '',
    tutor_nome: resumoLead.tutor_nome,
    tutor_telefone: resumoLead.tutor_telefone,
    cao_nome: resumoLead.cao_nome,
    cao_idade_anos: resumoLead.cao_idade_anos,
    cao_raca: resumoLead.cao_raca,
    cao_porte: resumoLead.cao_porte,
    cao_sexo: resumoLead.cao_sexo,
    cao_castrado: resumoLead.cao_castrado,
    cao_vacinas_ok: resumoLead.cao_vacinas_ok,
    cao_antipulgas_ok: resumoLead.cao_antipulgas_ok,
    cao_sociavel: resumoLead.cao_sociavel,
    cao_reativo: resumoLead.cao_reativo,
    unidade_preferida: resumoLead.unidade_preferida,
    servico_interesse: resumoLead.servico_interesse,
    data_hora_avaliacao: '',
    comprovante_recebido: resumoLead.comprovante_recebido,
    tipo_comprovante: resumoLead.tipo_comprovante,
    observacoes: resumoLead.observacoes
  };

  const syntheticContent =
    messageText ||
    '[FUP_MANUAL] Macro executada para gerar follow-up manual. Use o histórico consolidado como fonte principal.';

  const chatHistoryUuid =
    `account:${accountId}-contact:${contactId}-conversation:${conversationId}-phone:${phone}`;

  const payload = {
    gatilho: 'FUP_MANUAL',
    trigger_event: clean(body.event || 'macro.executed'),
    agent_name: 'Bruna',
    nome_agente: 'Bruna',
    should_reply: true,

    account_id: accountId,
    inbox_id: inboxId,
    conversation_id: conversationId,
    contact_id: contactId,
    current_message_id: messageId,

    phone,
    phone_digits: onlyDigits(phone),
    lead_name: leadName,
    can_reply: !!body.can_reply,
    conversation_status: clean(body.status || ''),
    labels,

    origem: clean(custom.origem || ''),
    anuncio: clean(custom.anuncio || ''),
    sender_identifier: clean(sender.identifier || ''),
    contact_last_seen_at: body.contact_last_seen_at || null,
    last_activity_at: body.last_activity_at || null,
    origem_fup: 'manual_chatwoot_macro',

    inputs: {
      status_lead: statusLead,
      ultima_intencao: ultimaIntencao,
      evento_sistema: eventoSistema,
      mensagens_resposta: [],

      resumo_lead: resumoLead,

      proxima_acao:
        leadSummaryParsed.proxima_acao ||
        'Gerar follow-up manual com base no histórico consolidado e no estado atual reconstruído pelo CRM.',

      deve_repassar_humano: toBool(custom.bruna_deve_repassar_humano, false),
      motivo_repasse: '',
      deve_enviar_guia: false,
      deve_solicitar_pagamento: false,
      deve_consultar_agenda: false,
      deve_criar_pre_reserva: false,
      deve_encerrar_conversa: false,

      resumo_interno_repasse: resumoInternoRepasse,

      is_first_turn: false,
      interpreted_message: hasAttachment ? 'attachment_message' : 'text_message',
      interpreted_modality: messageModality,
      interpreted_status: 'ok',
      supported_input: true,

      versao_regras_negocio: 'v1',
      versao_contrato_payload: 'v1'
    },

    memory: {
      phone,
      nome_tutor: resumoLead.tutor_nome,
      email_tutor: '',
      nome_cao: resumoLead.cao_nome,
      idade_cao_anos: resumoLead.cao_idade_anos,
      idade_cao_texto: resumoLead.cao_idade_texto,
      cao_raca: resumoLead.cao_raca,
      cao_porte: resumoLead.cao_porte,
      cao_sexo: resumoLead.cao_sexo,
      cao_castrado: resumoLead.cao_castrado,
      cao_no_cio: resumoLead.cao_no_cio,
      cao_vacinas_ok: resumoLead.cao_vacinas_ok,
      cao_antipulgas_ok: resumoLead.cao_antipulgas_ok,
      cao_vermifugacao_ok: resumoLead.cao_vermifugacao_ok,
      cao_sociavel: resumoLead.cao_sociavel,
      cao_reativo: resumoLead.cao_reativo,
      possui_relatorio_veterinario: resumoLead.possui_relatorio_veterinario,
      unidade_preferida: resumoLead.unidade_preferida,
      servico_interesse: resumoLead.servico_interesse,
      status_lead: statusLead,
      ultima_intencao: ultimaIntencao,
      evento_sistema_atual: eventoSistema,
      resumo_lead_json: resumoLead,
      resumo_interno_repasse_json: resumoInternoRepasse,
      account_id_chatwoot: accountId,
      contact_id_chatwoot: contactId,
      conversation_id_chatwoot: conversationId,
      chat_history_uuid: chatHistoryUuid
    },

    chatwoot: {
      chat_history_uuid: chatHistoryUuid,
      labels,
      system_event: eventoSistema,
      account_id: accountId,
      contact_id: contactId,
      message_id: messageId,
      conversation_id: conversationId,
      event: clean(body.event || ''),
      inbox_id: inboxId,
      can_reply: !!body.can_reply,
      conversation_status: clean(body.status || ''),
      assignee_id: body.meta?.assignee?.id || msg0.conversation?.assignee_id || null,
      team_id: body.meta?.team?.id || null
    },

    message: {
      id: messageId,
      message_id: messageId,
      current_message_id: messageId,
      message_modality: messageModality,
      has_text: hasText,
      has_attachment: hasAttachment,
      private: !!msg0.private,
      type: messageType,
      content: syntheticContent,
      content_raw: messageText,
      processed_message_content: clean(msg0.processed_message_content || ''),
      data_url: firstAttachment?.data_url || null,
      source_id: clean(msg0.source_id || ''),
      created_at: msg0.created_at || body.timestamp || null,
      content_type: clean(msg0.content_type || 'text'),
      attachment: firstAttachment
        ? {
            id: firstAttachment.id || null,
            file_type: clean(firstAttachment.file_type || ''),
            data_url: firstAttachment.data_url || null,
            file_size: firstAttachment.file_size || null,
            transcribed_text: clean(firstAttachment.transcribed_text || '')
          }
        : null
    },

    lead: {
      sender_name: leadName,
      phone,
      sender_identifier: clean(sender.identifier || ''),
      entry_channel: clean(custom.origem || ''),
      anuncio: clean(custom.anuncio || ''),
      link_rastreavel: clean(custom.link_rastreavel || ''),
      utms: {},
      sender_type: clean(sender.type || 'contact')
    },

    raw_source: body
  };

  return [{ json: payload }];
}

/* ============================================================
   CAMINHO 2: LINHA DA bruna_memoria_leads VINDA DO LOOP
   ============================================================ */

if (isMemoryRow) {
  const memoryRow = input;

  const resumoLeadJson = parseJsonMaybe(memoryRow.resumo_lead_json, {}) || {};
  const resumoRepasseJson = parseJsonMaybe(memoryRow.resumo_interno_repasse_json, {}) || {};
  const payloadUltimaResposta = parseJsonMaybe(memoryRow.payload_ultima_resposta_json, {}) || {};
  const dadosOrigemJson = parseJsonMaybe(memoryRow.dados_origem_json, {}) || {};
  const etiquetasJson = parseJsonMaybe(memoryRow.etiquetas_chatwoot_json, []) || [];

  const accountId = Number(
    memoryRow.account_id_chatwoot ||
    payloadUltimaResposta.chatwoot?.account_id ||
    dadosOrigemJson.account_id_chatwoot ||
    0
  );

  const contactId = Number(
    memoryRow.contact_id_chatwoot ||
    payloadUltimaResposta.chatwoot?.contact_id ||
    dadosOrigemJson.contact_id_chatwoot ||
    0
  );

  const conversationId = Number(
    memoryRow.conversation_id_chatwoot ||
    payloadUltimaResposta.chatwoot?.conversation_id ||
    dadosOrigemJson.conversation_id_chatwoot ||
    0
  );

  const inboxId = Number(
    payloadUltimaResposta.chatwoot?.inbox_id ||
    0
  );

  const currentMessageId = Number(
    memoryRow.last_processed_message_id ||
    payloadUltimaResposta.message?.current_message_id ||
    payloadUltimaResposta.chatwoot?.message_id ||
    0
  );

  const phone = clean(
    memoryRow.phone ||
    resumoLeadJson.tutor_telefone ||
    payloadUltimaResposta.lead?.phone ||
    ''
  );

  const leadName = clean(
    memoryRow.nome_tutor ||
    resumoLeadJson.tutor_nome ||
    payloadUltimaResposta.lead?.sender_name ||
    ''
  );

  const labels = Array.isArray(etiquetasJson)
    ? etiquetasJson.map(x => clean(x)).filter(Boolean)
    : Array.isArray(payloadUltimaResposta.chatwoot?.labels)
      ? payloadUltimaResposta.chatwoot.labels.map(x => clean(x)).filter(Boolean)
      : [];

  const statusLead = normalizeStatus(
    memoryRow.status_lead ||
    payloadUltimaResposta.inputs?.status_lead ||
    ''
  );

  const ultimaIntencao = normalizeIntent(
    memoryRow.ultima_intencao ||
    payloadUltimaResposta.inputs?.ultima_intencao ||
    ''
  );

  const eventoSistema = normalizeEvent(
    memoryRow.evento_sistema_atual ||
    payloadUltimaResposta.inputs?.evento_sistema ||
    ''
  );

  const resumoLead = {
    tutor_nome: clean(resumoLeadJson.tutor_nome || memoryRow.nome_tutor || leadName),
    tutor_telefone: clean(resumoLeadJson.tutor_telefone || memoryRow.phone || phone),
    email_tutor: clean(resumoLeadJson.email_tutor || memoryRow.email_tutor || ''),

    cao_nome: clean(resumoLeadJson.cao_nome || memoryRow.nome_cao || ''),
    cao_idade_anos: clean(resumoLeadJson.cao_idade_anos || memoryRow.idade_cao_anos || ''),
    cao_idade_texto: clean(resumoLeadJson.cao_idade_texto || memoryRow.idade_cao_texto || ''),
    cao_raca: clean(resumoLeadJson.cao_raca || memoryRow.cao_raca || ''),
    cao_porte: normalizeNaoDefinido(resumoLeadJson.cao_porte || memoryRow.cao_porte),
    cao_sexo: normalizeNaoInformado(resumoLeadJson.cao_sexo || memoryRow.cao_sexo),
    cao_castrado: normalizeNaoInformado(resumoLeadJson.cao_castrado || memoryRow.cao_castrado),
    cao_no_cio: normalizeNaoInformado(resumoLeadJson.cao_no_cio || memoryRow.cao_no_cio),

    cao_vacinas_ok: normalizeNaoInformado(resumoLeadJson.cao_vacinas_ok || memoryRow.cao_vacinas_ok),
    cao_antipulgas_ok: normalizeNaoInformado(resumoLeadJson.cao_antipulgas_ok || memoryRow.cao_antipulgas_ok),
    cao_vermifugacao_ok: normalizeNaoInformado(resumoLeadJson.cao_vermifugacao_ok || memoryRow.cao_vermifugacao_ok),
    cao_sociavel: normalizeNaoInformado(resumoLeadJson.cao_sociavel || memoryRow.cao_sociavel),
    cao_reativo: normalizeNaoInformado(resumoLeadJson.cao_reativo || memoryRow.cao_reativo),
    possui_relatorio_veterinario: normalizeNaoInformado(resumoLeadJson.possui_relatorio_veterinario || memoryRow.possui_relatorio_veterinario),

    unidade_preferida: normalizeNaoDefinido(resumoLeadJson.unidade_preferida || memoryRow.unidade_preferida),
    servico_interesse: normalizeNaoDefinido(resumoLeadJson.servico_interesse || memoryRow.servico_interesse),
    periodo_desejado: clean(resumoLeadJson.periodo_desejado || memoryRow.periodo_desejado || ''),
    data_desejada: clean(resumoLeadJson.data_desejada || memoryRow.data_desejada || ''),
    data_checkin_desejada: clean(resumoLeadJson.data_checkin_desejada || memoryRow.data_checkin_desejada || ''),
    data_checkout_desejada: clean(resumoLeadJson.data_checkout_desejada || memoryRow.data_checkout_desejada || ''),

    origem_lead: clean(resumoLeadJson.origem_lead || memoryRow.origem_lead || ''),
    origem_detalhada: clean(resumoLeadJson.origem_detalhada || memoryRow.origem_detalhada || ''),

    comprovante_recebido: toBool(resumoLeadJson.comprovante_recebido ?? memoryRow.comprovante_recebido, false),
    tipo_comprovante: normalizeNaoInformado(resumoLeadJson.tipo_comprovante || memoryRow.tipo_comprovante),
    arquivo_comprovante_referencia: clean(resumoLeadJson.arquivo_comprovante_referencia || memoryRow.arquivo_comprovante_referencia || ''),
