  const src = $json.fup || $json || {};

  const labels = Array.isArray(src.labels)
    ? src.labels.map(x => String(x || '').toLowerCase().trim())
    : [];

  const statusLead = String(
    src.status_lead ||
    src.inputs?.status_lead ||
    src.memory?.status_lead ||
    ''
  ).toUpperCase().trim();

  const conversationStatus = String(src.conversation_status || 'open').toLowerCase().trim();

  const bloqueiaPorLabel =
    labels.some(l => l === '50' || l.includes('50')) ||
    labels.some(l => l === '60' || l.includes('60')) ||
    labels.some(l => l === 'cliente' || l.includes('cliente')) ||
    labels.some(l => l === 'humano' || l.includes('humano')) ||
    labels.some(l => l === 'flavia' || l.includes('flavia')) ||
    labels.some(l => l.includes('transferido-flavia')) ||
    labels.some(l => l.includes('sem-fup')) ||
    labels.some(l => l.includes('nao-fazer-fup')) ||
    labels.some(l => l.includes('não-fazer-fup')) ||
    labels.some(l => l.includes('fup-bruna-bloqueado'));

  const bloqueiaPorStatus =
    statusLead === 'TRANSFERIDO_FLAVIA' ||
    statusLead === 'ENCERRADO_NAO_PERFIL' ||
    statusLead === 'ENCERRADO';

  const podeSeguir =
    src.can_reply !== false &&
    conversationStatus === 'open' &&
