const fup = (() => {
  try {
    return $('Normaliza Entrada FUP').first().json || {};
  } catch (e) {
    return {};
  }
})();

const memoryFromNode = (() => {
  try {
    return $('Get Memory').first().json || {};
  } catch (e) {
    return {};
  }
})();

function clean(value) {
  if (value === undefined || value === null) return '';
  return String(value)
    .replace(/[\u200B-\u200D\u2060\uFEFF]/g, ' ')
    .replace(/\uFFFD/g, ' ')
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n')
    .trim();
}

function toBool(value, fallback = false) {
  if (value === true) return true;
  if (value === false) return false;
  if (value === 1 || value === '1') return true;
  if (value === 0 || value === '0') return false;

  const v = clean(value).toLowerCase();

  if (['true', 'sim', 'yes', 'y'].includes(v)) return true;
  if (['false', 'nao', 'não', 'no', 'n'].includes(v)) return false;

  return fallback;
}

function parseJsonMaybe(value, fallback = {}) {
  if (value === undefined || value === null || value === '') return fallback;
  if (typeof value === 'object') return value;

  try {
    return JSON.parse(value);
  } catch (e) {
    return fallback;
  }
}

function toNum(value) {
  const n = Number(value);
  return Number.isFinite(n) && n > 0 ? n : 0;
}

function normalizeTextValue(value, fallback = '') {
  const v = clean(value);
  return v || fallback;
}

function normalizeNaoInformado(value) {
  const v = clean(value);
  return v || 'nao_informado';
}

function normalizeNaoDefinido(value) {
  const v = clean(value);
  return v || 'nao_definido';
}

function normalizeStatus(value) {
  const v = clean(value);

  const valid = [
    'NOVO_LEAD',
    'COLETANDO_DADOS',
    'QUALIFICANDO',
    'PRE_REPROVADO',
    'APTO_PARA_AVALIACAO',
    'AGUARDANDO_PAGAMENTO',
    'COMPROVANTE_RECEBIDO',
    'TRANSFERIDO_FLAVIA',
    'ENCERRADO_NAO_PERFIL',
    'ENCERRADO_SEM_RESPOSTA',
    'ENCERRADO'
  ];

  return valid.includes(v) ? v : 'QUALIFICANDO';
}

function normalizeIntent(value) {
  const v = clean(value);

  const valid = [
    'INTERESSE_CRECHE',
    'INTERESSE_HOTEL',
    'PEDIU_VALOR',
    'PEDIU_LOCALIZACAO',
    'PEDIU_VISITA',
    'INFORMOU_DADOS_CAO',
    'INFORMOU_DADOS_TUTOR',
    'ACEITOU_AVALIACAO',
    'RECEBEU_PIX',
    'ENVIOU_COMPROVANTE',
    'PEDIU_HUMANO',
    'MACHO_NAO_CASTRADO',
    'RACA_POTENCIAL_DANO',
    'URGENCIA_FERIADO',
    'OBJECAO_PRECO',
    'SUMIU'
  ];

  return valid.includes(v) ? v : 'SUMIU';
}

function normalizeEvent(value) {
  const v = clean(value);

  const valid = [
    '',
    'FORMULARIO_RECEBIDO',
    'GUIA_ENVIADO',
    'PIX_SOLICITADO',
    'ANEXO_RECEBIDO',
    'COMPROVANTE_IDENTIFICADO',
    'REPASSE_FLAVIA',
    'FOLLOWUP_DISPARADO',
    'CONVERSA_ENCERRADA'
  ];

  return valid.includes(v) ? v : '';
}

function getChatwootMessages(payloadUltimaResposta) {
  const candidates = [
    payloadUltimaResposta?.crm?.chatwoot?.chatwoot_messages,
    payloadUltimaResposta?.chatwoot?.chatwoot_messages,
    payloadUltimaResposta?.payload_base?.chatwoot?.chatwoot_messages
  ];

  for (const c of candidates) {
    if (Array.isArray(c)) return c;
  }

  return [];
}

function sortMessages(messages) {
  return [...messages].sort((a, b) => {
    const ca = Number(a.created_at || 0);
    const cb = Number(b.created_at || 0);

    if (ca !== cb) return ca - cb;

    return Number(a.id || 0) - Number(b.id || 0);
  });
}

function isLeadMessage(msg) {
  const role = clean(msg.role).toLowerCase();
  const roleLabel = clean(msg.role_label).toLowerCase();
  const senderType = clean(msg.sender_type).toLowerCase();
  const messageType = Number(msg.message_type);

  return (
    role === 'lead' ||
    roleLabel === 'lead' ||
    senderType === 'contact' ||
    messageType === 0
  );
}

function isOutgoingMessage(msg) {
  const role = clean(msg.role).toLowerCase();
  const senderType = clean(msg.sender_type).toLowerCase();
  const messageType = Number(msg.message_type);

  return (
    role === 'bruna' ||
    role === 'humano' ||
    senderType === 'user' ||
    messageType === 1
  );
}

/*
  Escolhe a melhor origem de memória.

  1. Preferência: Get Memory
  2. Fallback: raw_source do Normaliza Entrada FUP
  3. Fallback: fup.memory
*/
const memory =
  Object.keys(memoryFromNode || {}).length
    ? memoryFromNode
    : (
        fup.raw_source && fup.raw_source.phone
          ? fup.raw_source
          : (fup.memory || {})
      );

const fupInputs = fup.inputs || {};
const fupResumoLead = fupInputs.resumo_lead || {};
const fupResumoRepasse = fupInputs.resumo_interno_repasse || {};
const fupChatwoot = fup.chatwoot || {};
const fupMessage = fup.message || {};
const fupLead = fup.lead || fup.fup || {};

const memoryResumoLead = parseJsonMaybe(memory.resumo_lead_json, {});
const memoryResumoRepasse = parseJsonMaybe(memory.resumo_interno_repasse_json, {});
const memoryPayloadUltimaResposta = parseJsonMaybe(memory.payload_ultima_resposta_json, {});
const memoryDadosOrigem = parseJsonMaybe(memory.dados_origem_json, {});
const memoryEtiquetas = parseJsonMaybe(memory.etiquetas_chatwoot_json, []);

const crmSnapshot = memoryPayloadUltimaResposta.crm || {};
const crmSnapshotMessage = crmSnapshot.message || {};
const crmSnapshotInputs = crmSnapshot.inputs || {};
const crmSnapshotLead = crmSnapshot.lead || {};

const chatwootMessages = sortMessages(getChatwootMessages(memoryPayloadUltimaResposta));
const latestAnyMessage = chatwootMessages.length ? chatwootMessages[chatwootMessages.length - 1] : null;
const latestLeadMessage = [...chatwootMessages].reverse().find(isLeadMessage) || null;
const latestOutgoingMessage = [...chatwootMessages].reverse().find(isOutgoingMessage) || null;

const accountId = Number(
  fup.account_id ||
  fupChatwoot.account_id ||
  memory.account_id_chatwoot ||
  memoryDadosOrigem.account_id_chatwoot ||
  crmSnapshot.chatwoot?.account_id ||
  memoryPayloadUltimaResposta.chatwoot?.account_id ||
  latestAnyMessage?.account_id ||
  0
);

const inboxId = Number(
  fup.inbox_id ||
  fupChatwoot.inbox_id ||
  memoryPayloadUltimaResposta.chatwoot?.inbox_id ||
  crmSnapshot.chatwoot?.inbox_id ||
  latestAnyMessage?.inbox_id ||
  0
);

const conversationId = Number(
  fup.conversation_id ||
  fupChatwoot.conversation_id ||
  memory.conversation_id_chatwoot ||
  memoryDadosOrigem.conversation_id_chatwoot ||
  crmSnapshot.chatwoot?.conversation_id ||
  memoryPayloadUltimaResposta.chatwoot?.conversation_id ||
  latestAnyMessage?.conversation_id ||
  0
);

const contactId = Number(
  fup.contact_id ||
  fupChatwoot.contact_id ||
  memory.contact_id_chatwoot ||
  memoryDadosOrigem.contact_id_chatwoot ||
  crmSnapshot.chatwoot?.contact_id ||
  memoryPayloadUltimaResposta.chatwoot?.contact_id ||
  0
);

const phone = clean(
  fup.phone ||
  fupLead.phone ||
  memory.phone ||
  memoryResumoLead.tutor_telefone ||
  fupResumoLead.tutor_telefone ||
  crmSnapshotLead.phone ||
  ''
);

const leadName = clean(
  fup.lead_name ||
  fupLead.sender_name ||
  memory.nome_tutor ||
  memoryResumoLead.tutor_nome ||
  fupResumoLead.tutor_nome ||
  crmSnapshotLead.sender_name ||
  latestLeadMessage?.sender_name ||
  ''
);

const labels = Array.isArray(fup.labels)
  ? fup.labels.map(x => clean(x)).filter(Boolean)
  : Array.isArray(fupChatwoot.labels)
