function clean(value) {
  if (value === undefined || value === null) return '';
  return String(value)
    .replace(/[\u200B-\u200D\u2060\uFEFF]/g, ' ')
    .replace(/\uFFFD/g, ' ')
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n')
    .trim();
}

function normText(value) {
  return clean(value)
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase();
}

function toNum(value) {
  const n = Number(value);
  return Number.isFinite(n) && n > 0 ? n : 0;
}

function getChatwootMessages(root) {
  const candidates = [
    root.chatwoot?.chatwoot_messages,
    root.chatwoot_messages,
    root.message?.chatwoot_messages,
    root.payload_base?.chatwoot?.chatwoot_messages,
    root.payload_base?.crm?.chatwoot?.chatwoot_messages,
    root.crm?.chatwoot?.chatwoot_messages,
    root.raw?.chatwoot_messages,
    root.raw?.payload,
    root.payload,
    root.messages,
    root.data
  ];

  for (const c of candidates) {
    if (Array.isArray(c)) return c;
  }

  return [];
}

function sortMessages(messages) {
  return [...messages]
    .filter(m => toNum(m?.id))
    .sort((a, b) => {
      const ca = Number(a.created_at || 0);
      const cb = Number(b.created_at || 0);

      if (ca !== cb) return ca - cb;

      return Number(a.id || 0) - Number(b.id || 0);
    });
}

function isLeadMessage(msg) {
  const role = normText(msg.role);
  const roleLabel = normText(msg.role_label);
  const senderType = normText(msg.sender_type);
  const senderOriginalType = normText(msg.sender_original_type);
  const messageType = Number(msg.message_type ?? msg.original_message_type);

  return (
    role === 'lead' ||
    roleLabel === 'lead' ||
    senderType === 'contact' ||
    senderOriginalType === 'contact' ||
    messageType === 0
  );
}

function isOutgoingMessage(msg) {
  const role = normText(msg.role);
  const senderType = normText(msg.sender_type);
  const senderOriginalType = normText(msg.sender_original_type);
  const messageType = Number(msg.message_type ?? msg.original_message_type);

  return (
    role === 'bruna' ||
    role === 'humano' ||
    senderType === 'user' ||
    senderOriginalType === 'user' ||
    messageType === 1
  );
}

