);

const sinalTextoTecnico =
  contentNorm.includes('formulario_sem_resposta') ||
  contentNorm.includes('fup_automatico_sem_message_id') ||
  contentNorm.includes('buscar historico completo');

const temHistoricoArray = chatwootMessages.length > 0;
const temMensagemLeadNoHistorico = !!latestLeadMessage?.id;
const temMensagemOutgoingNoHistorico = !!latestOutgoingMessage?.id;

const formularioSemResposta =
  crmMessage.formulario_sem_resposta === true ||
  crmMessage.sem_mensagem_do_lead === true ||
  sinalTextoTecnico ||
  (
    sinalSemMessageId &&
    temHistoricoArray &&
    !temMensagemLeadNoHistorico &&
    temMensagemOutgoingNoHistorico
  );

const semMensagemDoLead = formularioSemResposta;

const anchorMessage =
  resolvedMessageId
    ? (
        chatwootMessages.find(m => Number(m.id) === Number(resolvedMessageId)) ||
        latestAnyMessage ||
        null
      )
    : null;

const lastLeadText = semMensagemDoLead
  ? ''
  : clean(
      latestLeadMessage?.content ||
      memory.mensagem_ultima_lead ||
      crmMessage.current_lead_block_text ||
      crmMessage.content_raw ||
      ''
    );

const lastBrunaMessage = clean(
  memory.mensagem_ultima_bruna ||
  latestOutgoingMessage?.content ||
  crmMessage.last_bruna_message_before_current_block ||
  ''
);

const resolvedMessageContent = semMensagemDoLead
  ? '[FORMULARIO_SEM_RESPOSTA] Lead entrou por formulário/anúncio, recebeu a primeira abordagem e ainda não respondeu.'
  : clean(
      anchorMessage?.content ||
      crmMessage.content ||
      crmMessage.content_raw ||
      crmMessage.current_lead_block_text ||
      lastLeadText ||
      ''
    );

const resolvedMessageType = semMensagemDoLead
  ? 'outgoing'
  : anchorMessage
    ? (isLeadMessage(anchorMessage) ? 'incoming' : 'outgoing')
    : clean(crmMessage.type || 'incoming');

const crmMessageResolvida = {
  ...crmMessage,

  id: resolvedMessageId || crmMessage.id || null,
  message_id: resolvedMessageId || crmMessage.message_id || null,
  current_message_id: resolvedMessageId || crmMessage.current_message_id || null,

  type: resolvedMessageType,

  content: resolvedMessageContent || crmMessage.content || '',
  content_raw: resolvedMessageContent || crmMessage.content_raw || '',
  processed_message_content: resolvedMessageContent || crmMessage.processed_message_content || '',

  current_lead_block_text: semMensagemDoLead ? '' : (lastLeadText || resolvedMessageContent || ''),
  last_bruna_message_before_current_block: lastBrunaMessage,

  first_message_id: toNum(crmMessage.first_message_id) || toNum(chatwootMessages[0]?.id) || null,
  last_message_id: toNum(crmMessage.last_message_id) || toNum(latestAnyMessage?.id) || resolvedMessageId || null,

  sem_mensagem_do_lead: semMensagemDoLead,
  formulario_sem_resposta: formularioSemResposta,

  anchor_resolvida_no_fup: true
};

const crmRootResolvido = {
  ...crmRoot,
  current_message_id: resolvedMessageId || crmRoot.current_message_id || null,
  message: crmMessageResolvida,
  chatwoot: {
    ...crmChatwoot,
    message_id: resolvedMessageId || crmChatwoot.message_id || null,
    chatwoot_messages: chatwootMessages.length
      ? chatwootMessages
      : crmChatwoot.chatwoot_messages
  },
  resolve_ancora_fup_debug: {
    ok: true,
    current_message_id_original: currentMessageIdOriginal || null,
    resolved_message_id: resolvedMessageId || null,
    latest_any_message_id: latestAnyMessage?.id || null,
    latest_lead_message_id: latestLeadMessage?.id || null,
    latest_outgoing_message_id: latestOutgoingMessage?.id || null,
    sem_mensagem_do_lead: semMensagemDoLead,
    formulario_sem_resposta: formularioSemResposta,
    resolved_message_type: resolvedMessageType,
    resolved_message_preview: resolvedMessageContent.slice(0, 180)
  }
};

/* ============================================================
   2. BASES DO FUP
   ============================================================ */

const labels = Array.isArray(crmChatwoot.labels)
  ? crmChatwoot.labels.map(x => clean(x).toLowerCase()).filter(Boolean)
  : Array.isArray(norm.labels)
    ? norm.labels.map(x => clean(x).toLowerCase()).filter(Boolean)
    : [];

const statusBase = clean(crm.status_lead || memory.status_lead || 'QUALIFICANDO');
const intencaoBase = clean(crm.ultima_intencao || memory.ultima_intencao || 'SUMIU');
const eventoBase = clean(crm.evento_sistema || memory.evento_sistema_atual || '');

const contadorFollowup = Number(
  memory.contador_followup ||
  crmMemory.contador_followup ||
  norm.contador_followup ||
  0
);

const tipoUltimoFollowup = clean(
  memory.tipo_ultimo_followup ||
  crmMemory.tipo_ultimo_followup ||
  norm.tipo_ultimo_followup ||
  ''
);

const ultimoFollowupEm =
  memory.ultimo_followup_em ||
  crmMemory.ultimo_followup_em ||
  norm.ultimo_followup_em ||
  null;

const tiposFup = Array.isArray(cfg.tipos_followup) ? cfg.tipos_followup : [];
const maxFollowups = Number(cfg.max_followups || 5);
const bloquearAposLimite = cfg.bloquear_apos_limite !== false;

const limiteFollowupAtingido = contadorFollowup >= maxFollowups;

const bloqueiaPorLabel =
  labels.some(l => l.includes('cliente')) ||
  labels.some(l => l.includes('humano')) ||
  labels.some(l => l.includes('flavia')) ||
  labels.some(l => l.includes('transferido-flavia')) ||
  labels.some(l => l.includes('sem-fup')) ||
  labels.some(l => l.includes('nao-fazer-fup')) ||
  labels.some(l => l.includes('não-fazer-fup')) ||
  labels.some(l => l.includes('fup-bruna-bloqueado'));

const bloqueiaPorStatus = [
  'TRANSFERIDO_FLAVIA',
  'COMPROVANTE_RECEBIDO',
  'ENCERRADO_NAO_PERFIL',
  'ENCERRADO'
].includes(statusBase);

const conversationStatus = clean(
  crmChatwoot.conversation_status ||
  norm.conversation_status ||
  'open'
).toLowerCase();

const idsOk =
  !!Number(crmChatwoot.account_id || norm.account_id || memory.account_id_chatwoot || 0) &&
  !!Number(crmChatwoot.conversation_id || norm.conversation_id || memory.conversation_id_chatwoot || 0);

const phoneOk = !!clean(
  crmLead.phone ||
  memory.phone ||
  norm.phone ||
  crm.resumo_lead?.tutor_telefone ||
  ''
);

const shouldReplyOk =
  crmRoot.should_reply !== false &&
  norm.should_reply !== false;

const conversaAbertaOk =
  !conversationStatus || conversationStatus === 'open';

const motivosBloqueio = [];

if (limiteFollowupAtingido && bloquearAposLimite) {
  motivosBloqueio.push(`Limite de follow-ups atingido. contador_followup=${contadorFollowup}, max_followups=${maxFollowups}`);
}

if (bloqueiaPorLabel) {
  motivosBloqueio.push('Conversa possui label de bloqueio/humano/cliente/sem-fup.');
}

if (bloqueiaPorStatus) {
  motivosBloqueio.push(`Status bloqueado para FUP: ${statusBase}`);
}

if (!idsOk) {
  motivosBloqueio.push('IDs obrigatórios ausentes: account_id ou conversation_id.');
}

if (!phoneOk) {
  motivosBloqueio.push('Telefone ausente.');
}

if (!shouldReplyOk) {
  motivosBloqueio.push('should_reply=false.');
}

if (!conversaAbertaOk) {
  motivosBloqueio.push(`Conversa não está aberta: ${conversationStatus}`);
}

if (sinalSemMessageId && !resolvedMessageId && !clean(crmMessage.history_for_crm)) {
  motivosBloqueio.push('Histórico não retornou mensagem real nem history_for_crm suficiente para FUP.');
}

const podeGerarFup = motivosBloqueio.length === 0;

const proximoNumeroFup = limiteFollowupAtingido
  ? maxFollowups
  : Math.min(contadorFollowup + 1, maxFollowups);

const tipoCfg = tiposFup.find(t => Number(t.numero) === proximoNumeroFup) || tiposFup[0] || {
  tipo: 'FUP_1_RETOMADA_LEVE',
  tag: 'fup-bruna-1',
  estrategia_padrao: 'RETOMADA_LEVE',
  objetivo_padrao: 'retomar a conversa com baixa fricção',
  tom_padrao: 'leve, humano e direto'
};

let tipoFollowupSugerido = tipoCfg.tipo;
let estrategia = tipoCfg.estrategia_padrao;
let objetivo = tipoCfg.objetivo_padrao;
let tom = tipoCfg.tom_padrao;

/* ============================================================
   3. ESTRATÉGIA
   ============================================================ */

if (formularioSemResposta) {
  estrategia = 'RETOMADA_FORMULARIO_SEM_RESPOSTA';
  objetivo = 'retomar o interesse de um lead que veio por formulário/anúncio e ainda não respondeu a primeira abordagem';
  tom = 'leve, cordial e direto';
} else {
  if (statusBase === 'COLETANDO_DADOS') {
    estrategia = 'RETOMAR_COLETA';
    objetivo = 'retomar a coleta do próximo dado faltante sem parecer checklist';
  }

  if (statusBase === 'QUALIFICANDO') {
    estrategia = 'RETOMADA_LEVE';
    objetivo = 'reabrir a conversa e puxar o próximo passo com baixa fricção';
  }

  if (statusBase === 'PRE_REPROVADO') {
    estrategia = 'DESTRAVAR_RESTRICAO';
    objetivo = 'retomar a restrição atual com cuidado';
    tom = 'cuidadoso e respeitoso';
  }

  if (statusBase === 'APTO_PARA_AVALIACAO') {
    estrategia = 'DESTRAVAR_AVALIACAO';
    objetivo = 'entender se o tutor quer seguir com a avaliação';
    tom = 'consultivo e objetivo';
  }

  if (statusBase === 'AGUARDANDO_PAGAMENTO') {
    estrategia = 'LEMBRAR_PAGAMENTO';
    objetivo = 'retomar o próximo passo sem soar como cobrança dura';
    tom = 'operacional leve';
  }

  if (statusBase === 'COMPROVANTE_RECEBIDO') {
    estrategia = 'AGUARDAR_CONFERENCIA';
    objetivo = 'reforçar que a equipe segue com conferência humana, sem prometer aprovação';
    tom = 'tranquilo e operacional';
  }

  if (statusBase === 'TRANSFERIDO_FLAVIA') {
    estrategia = 'NAO_INVASIVO_HUMANO';
    objetivo = 'não atropelar atendimento humano, apenas deixar porta aberta se fizer sentido';
    tom = 'muito breve e não invasivo';
  }

  if (statusBase === 'ENCERRADO_NAO_PERFIL') {
    estrategia = 'PORTA_ABERTA_FUTURA';
    objetivo = 'manter porta aberta para futuro sem contrariar a regra atual';
    tom = 'respeitoso e elegante';
  }

  if (statusBase === 'ENCERRADO_SEM_RESPOSTA' || statusBase === 'ENCERRADO') {
    estrategia = contadorFollowup >= (maxFollowups - 1) ? 'FECHAMENTO_ELEGANTE' : 'REATIVACAO_LEVE';
    objetivo = contadorFollowup >= (maxFollowups - 1)
      ? 'encerrar com elegância e sem insistência'
      : 'reativar a conversa com suavidade';
    tom = contadorFollowup >= (maxFollowups - 1) ? 'elegante e breve' : 'leve e amistoso';
  }

  if (intencaoBase === 'PEDIU_VALOR' || intencaoBase === 'OBJECAO_PRECO') {
    estrategia = 'DESTRAVAR_DECISAO';
    objetivo = 'destravar a decisão respeitando preço, dúvida ou comparação';
    tom = 'consultivo e sem pressão';
  }

  if (intencaoBase === 'MACHO_NAO_CASTRADO') {
    estrategia = statusBase === 'ENCERRADO_NAO_PERFIL'
      ? 'PORTA_ABERTA_FUTURA'
      : 'DESTRAVAR_RESTRICAO';

    objetivo = statusBase === 'ENCERRADO_NAO_PERFIL'
      ? 'manter porta aberta caso a castração aconteça no futuro'
      : 'retomar a pergunta sobre intenção de castrar em breve';

    tom = 'respeitoso e claro';
  }

  if (intencaoBase === 'RACA_POTENCIAL_DANO') {
    estrategia = 'PORTA_ABERTA_FUTURA';
    objetivo = 'encerrar com respeito, sem oferecer avaliação';
    tom = 'respeitoso e firme';
  }
}

/* ============================================================
   4. RESTRIÇÕES E ALERTAS
   ============================================================ */

const restricoes = [
  'não usar abertura inicial completa',
  'não se apresentar como se fosse primeiro atendimento do zero',
  'não inventar agenda',
  'não oferecer horário',
  'não confirmar disponibilidade',
  'não validar pagamento',
  'não confirmar hospedagem',
  'não contradizer o estado reconstruído pelo CRM',
  'se message.type for outgoing, não tratar message.content como nova fala do lead'
];

if (formularioSemResposta) {
  restricoes.push('não dizer que o lead sumiu depois de conversar, pois ele apenas não respondeu a primeira abordagem');
  restricoes.push('não dizer que ele conseguiu ou não conseguiu reunir informações do cão, porque ele ainda não conversou');
  restricoes.push('não mencionar histórico como se houvesse conversa ativa do lead');
  restricoes.push('retomar o interesse vindo do formulário/anúncio de forma leve');
  restricoes.push('pode dizer que viu que ele deixou contato ou pediu informações, se isso estiver coerente com a origem');
}

if (crm.deve_repassar_humano === true || labels.includes('transferido-flavia') || labels.includes('flavia') || labels.includes('humano')) {
  restricoes.push('não atropelar atendimento humano');
}

if (crm.deve_consultar_agenda === true) {
  restricoes.push('não inventar agenda nem horário');
}

if (crm.deve_criar_pre_reserva === true) {
  restricoes.push('não confirmar operação interna nem pré-reserva');
}

if (crm.deve_solicitar_pagamento === true) {
  restricoes.push('se mencionar pagamento, manter tom leve');
}

if (statusBase === 'ENCERRADO_NAO_PERFIL') {
  restricoes.push('não oferecer avanço operacional incompatível com o perfil atual');
}

if (intencaoBase === 'MACHO_NAO_CASTRADO') {
  restricoes.push('se estiver encerrado, só deixar porta aberta caso haja castração futura');
}

if (intencaoBase === 'RACA_POTENCIAL_DANO') {
  restricoes.push('não sugerir exceção para raça com potencial de dano');
}

const alertas = [];

if (formularioSemResposta) {
  alertas.push('lead_de_formulario_sem_resposta');
}

if (semMensagemDoLead) {
  alertas.push('sem_mensagem_real_do_lead_no_historico');
}

if (sinalSemMessageId) {
  alertas.push('entrada_original_sem_message_id_resolvida_por_historico');
}

if (tipoUltimoFollowup) {
  alertas.push(`tipo_ultimo_followup=${tipoUltimoFollowup}`);
}

if (limiteFollowupAtingido) {
  alertas.push(`limite_configurado_atingido=${maxFollowups}`);
}

if (labels.includes('01-em-atendimento') || labels.includes('01-bruna-atendimento')) {
  alertas.push('conversa_com_label_de_atendimento');
}

if (crmMessageResolvida.type === 'outgoing') {
  alertas.push('message_type_outgoing_no_contexto_do_crm');
}

if (crm?.diagnostico_crm?.humano_assumiu === true) {
  alertas.push('diagnostico_crm_humano_assumiu=true');
}

const motivoBloqueio = !podeGerarFup
  ? motivosBloqueio.join(' | ')
  : '';

const resumoLeadAtual = crm.resumo_lead || {};
const resumoInternoRepasse = crm.resumo_interno_repasse || {};

const guiaIa = [
  `pode_gerar_fup=${podeGerarFup}`,
  `motivo_bloqueio=${motivoBloqueio}`,
  `status_base=${statusBase}`,
  `ultima_intencao_base=${intencaoBase}`,
  `evento_sistema_base=${eventoBase}`,
  `contador_followup=${contadorFollowup}`,
  `max_followups=${maxFollowups}`,
  `proximo_numero_followup=${proximoNumeroFup}`,
  `limite_followup_atingido=${limiteFollowupAtingido}`,
  `tipo_ultimo_followup=${tipoUltimoFollowup}`,
  `tipo_followup_sugerido=${tipoFollowupSugerido}`,
  `estrategia_fup=${estrategia}`,
  `objetivo_fup=${objetivo}`,
  `tom=${tom}`,
  `formulario_sem_resposta=${formularioSemResposta}`,
  `sem_mensagem_do_lead=${semMensagemDoLead}`,
  `anchor_message_id=${resolvedMessageId || ''}`,
  `anchor_message_type=${crmMessageResolvida.type || ''}`,
  `ultima_mensagem_real_lead=${lastLeadText}`,
  `ultima_mensagem_real_bruna=${lastBrunaMessage}`,
  `restricoes=${restricoes.join(' | ')}`,
  `alertas=${alertas.join(' | ')}`
].join('\n');

/* ============================================================
   5. SAÍDA
   ============================================================ */

return [
  {
    json: {
      pode_gerar_fup: podeGerarFup,
      motivo_bloqueio: motivoBloqueio,

      status_base: statusBase,
      ultima_intencao_base: intencaoBase,
      evento_sistema_base: eventoBase,

      contador_followup_atual: contadorFollowup,
      tipo_ultimo_followup: tipoUltimoFollowup,
      ultimo_followup_em: ultimoFollowupEm,

      max_followups: maxFollowups,
      proximo_numero_followup: proximoNumeroFup,
      limite_followup_atingido: limiteFollowupAtingido,

      tipo_followup_sugerido: tipoFollowupSugerido,
      estrategia_fup: estrategia,
      objetivo_fup: objetivo,
      recomendacao_tom: tom,
      restricoes_fup: restricoes,
      alertas_contexto: alertas,

      formulario_sem_resposta: formularioSemResposta,
      sem_mensagem_do_lead: semMensagemDoLead,

      anchor_message_id: resolvedMessageId || null,
      anchor_message_type: crmMessageResolvida.type || '',
      ultima_mensagem_real_lead: lastLeadText,
      ultima_mensagem_real_bruna: lastBrunaMessage,
      message_resolvida: crmMessageResolvida,

      resumo_lead_atual: resumoLeadAtual,
      resumo_interno_repasse: resumoInternoRepasse,

      contexto_operacional: {
        pode_gerar_fup: podeGerarFup,
        motivo_bloqueio: motivoBloqueio,

        status_base: statusBase,
        ultima_intencao_base: intencaoBase,
        evento_sistema_base: eventoBase,

        contador_followup_atual: contadorFollowup,
        tipo_ultimo_followup: tipoUltimoFollowup,
        ultimo_followup_em: ultimoFollowupEm,

        max_followups: maxFollowups,
        proximo_numero_followup: proximoNumeroFup,
        limite_followup_atingido: limiteFollowupAtingido,

        tipo_followup_sugerido: tipoFollowupSugerido,
        estrategia_fup: estrategia,
        objetivo_fup: objetivo,
        recomendacao_tom: tom,

        formulario_sem_resposta: formularioSemResposta,
        sem_mensagem_do_lead: semMensagemDoLead,

        anchor_message_id: resolvedMessageId || null,
        anchor_message_type: crmMessageResolvida.type || '',
        ultima_mensagem_real_lead: lastLeadText,
        ultima_mensagem_real_bruna: lastBrunaMessage,

        restricoes_fup: restricoes,
        alertas_contexto: alertas,

        resumo_lead_atual: resumoLeadAtual,
        resumo_interno_repasse: resumoInternoRepasse,
        message_resolvida: crmMessageResolvida
      },

      config_followup: cfg,

      crm_snapshot: crmRootResolvido,
      crm_snapshot_original: crmRoot,

      guia_ia: guiaIa
    }
  }
];

const src = $('Gerador de FUP').first().json || {};
const ctx = $('Preparar Contexto FUP').first().json || {};
const cfg = $('CONFIG REGRAS FUP').first().json || {};

const rawCandidates = [
  src.output,
  src.text,
  src.response,
  src.content,
  src.message?.content,
  Array.isArray(src.messages) ? src.messages[0]?.content : undefined,
  typeof src === 'string' ? src : undefined
].filter(v => typeof v === 'string' && v.trim());

let raw = rawCandidates[0] || JSON.stringify(src);
raw = String(raw).trim();
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();

const jsonMatch = raw.match(/\{[\s\S]*\}/);

if (!jsonMatch) {
  throw new Error('Não foi encontrado JSON na saída do modelo. RAW: ' + raw);
}

let jsonText = jsonMatch[0]
  .replace(/[\u201C\u201D]/g, '"')
  .replace(/[\u2018\u2019]/g, "'")
  .replace(/,\s*([}\]])/g, '$1')
  .trim();

let parsed;

try {
  parsed = JSON.parse(jsonText);
} catch (e) {
  throw new Error('Falha ao fazer parse do JSON do modelo: ' + e.message + ' | RAW: ' + jsonText);
}

const tiposConfig = Array.isArray(cfg.tipos_followup) ? cfg.tipos_followup : [];

const tiposValidos = tiposConfig.map(t => t.tipo).filter(Boolean);

if (!tiposValidos.length) {
  tiposValidos.push(
    'FUP_1_RETOMADA_LEVE',
    'FUP_2_DESTRAVA_OBJETIVO',
    'FUP_3_REFORCO_VALOR',
    'FUP_4_DECISAO_FINAL',
    'FUP_5_FECHAMENTO_ELEGANTE'
  );
}

const statusValidos = [
  'NOVO_LEAD',
  'COLETANDO_DADOS',
  'QUALIFICANDO',
  'PRE_REPROVADO',
  'APTO_PARA_AVALIACAO',
  'AGUARDANDO_PAGAMENTO',
  'COMPROVANTE_RECEBIDO',
  'TRANSFERIDO_FLAVIA',
  'ENCERRADO_NAO_PERFIL',
  'ENCERRADO_SEM_RESPOSTA',
  'ENCERRADO'
];

const intencoesValidas = [
  'INTERESSE_CRECHE',
  'INTERESSE_HOTEL',
  'PEDIU_VALOR',
  'PEDIU_LOCALIZACAO',
  'PEDIU_VISITA',
  'INFORMOU_DADOS_CAO',
  'INFORMOU_DADOS_TUTOR',
  'ACEITOU_AVALIACAO',
  'RECEBEU_PIX',
  'ENVIOU_COMPROVANTE',
  'PEDIU_HUMANO',
  'MACHO_NAO_CASTRADO',
  'RACA_POTENCIAL_DANO',
  'URGENCIA_FERIADO',
  'OBJECAO_PRECO',
  'SUMIU'
];

const defaultTagsAdd = {};

for (const t of tiposConfig) {
  if (t.tipo && t.tag) {
    defaultTagsAdd[t.tipo] = [t.tag];
  }
}

if (!Object.keys(defaultTagsAdd).length) {
  defaultTagsAdd.FUP_1_RETOMADA_LEVE = ['fup-bruna-1'];
  defaultTagsAdd.FUP_2_DESTRAVA_OBJETIVO = ['fup-bruna-2'];
  defaultTagsAdd.FUP_3_REFORCO_VALOR = ['fup-bruna-3'];
  defaultTagsAdd.FUP_4_DECISAO_FINAL = ['fup-bruna-4'];
  defaultTagsAdd.FUP_5_FECHAMENTO_ELEGANTE = ['fup-bruna-5'];
}

let tipo_followup = String(parsed.tipo_followup || '').trim();

if (!tiposValidos.includes(tipo_followup)) {
  tipo_followup = ctx.tipo_followup_sugerido || 'FUP_1_RETOMADA_LEVE';
}

let mensagens_resposta = [];

if (Array.isArray(parsed.mensagens_resposta)) {
  mensagens_resposta = parsed.mensagens_resposta
    .map(x => String(x || '').trim())
    .filter(Boolean)
    .slice(0, 2);
}

if (!mensagens_resposta.length && typeof parsed.mensagens_resposta === 'string') {
  mensagens_resposta = String(parsed.mensagens_resposta)
    .split(/\n{2,}/)
    .map(x => x.trim())
    .filter(Boolean)
    .slice(0, 2);
}

if (!mensagens_resposta.length && typeof parsed.mensagem === 'string') {
  mensagens_resposta = [String(parsed.mensagem).trim()].filter(Boolean);
}

let pode_enviar = typeof parsed.pode_enviar === 'boolean'
  ? parsed.pode_enviar
  : mensagens_resposta.length > 0;

if (ctx.pode_gerar_fup === false) {
  pode_enviar = false;
  mensagens_resposta = [];
}

let status_lead_novo = String(parsed.status_lead_novo || '').trim();

if (!statusValidos.includes(status_lead_novo)) {
  status_lead_novo = statusValidos.includes(ctx.status_base)
    ? ctx.status_base
    : 'QUALIFICANDO';
}

let ultima_intencao_nova = String(parsed.ultima_intencao_nova || '').trim();

if (!intencoesValidas.includes(ultima_intencao_nova)) {
  ultima_intencao_nova = 'SUMIU';
}

const evento_sistema_novo = 'FOLLOWUP_DISPARADO';

let resumo_followup = String(parsed.resumo_followup || '').trim();

if (!resumo_followup) {
  resumo_followup = ctx.pode_gerar_fup === false
    ? `Follow-up não enviado. ${ctx.motivo_bloqueio || 'Bloqueado por regra operacional.'}`
    : `Follow-up ${tipo_followup} gerado pela Bruna.`;
}

let tags_add = Array.isArray(parsed.tags_add)
  ? parsed.tags_add.map(x => String(x || '').trim()).filter(Boolean)
  : [];

if (!tags_add.length && pode_enviar) {
  tags_add = defaultTagsAdd[tipo_followup] || ['fup-bruna-1'];
}

let tags_remove = Array.isArray(parsed.tags_remove)
  ? parsed.tags_remove.map(x => String(x || '').trim()).filter(Boolean)
  : [];

const tagsFollowup = Array.isArray(cfg.tags_followup) ? cfg.tags_followup : [];
const tagAtual = tags_add[0] || '';

tags_remove = [
  ...new Set([
    ...tags_remove,
    ...(tagsFollowup.filter(tag => tag !== tagAtual)),
    cfg.tag_bloqueio || 'fup-bruna-bloqueado'
  ])
];

if (!pode_enviar) {
  mensagens_resposta = [];
  tags_add = [];
}

const mensagem_fup = mensagens_resposta.join('\n\n');

return [
  {
    json: {
      pode_enviar,
      tipo_followup,
      mensagens_resposta,
      mensagem_fup,
      status_lead_novo,
      ultima_intencao_nova,
      evento_sistema_novo,
      resumo_followup,
      tags_add,
      tags_remove,
      contador_followup_atual: Number(ctx.contador_followup_atual || 0),
      raw_model_output: raw
    }
  }
];

const fup = $('PARSE FUP JSON').first().json || {};

const crmRoot = $('Gera Resumo Histórico Longo').first().json || {};
const crm = crmRoot.inputs || {};
const crmMessage = crmRoot.message || {};
const crmChatwoot = crmRoot.chatwoot || {};
const crmMemory = crmRoot.memory || {};
const crmLead = crmRoot.lead || {};

const ctx = $('Preparar Contexto FUP').first().json || {};

const memory = (() => {
  try {
    return $('Get Memory').first()?.json || crmMemory || {};
  } catch (e) {
    return crmMemory || {};
  }
})();

const norm = (() => {
  try {
    return $('Normaliza Entrada FUP').first()?.json || {};
  } catch (e) {
    return {};
  }
})();

const cfg = $('CONFIG REGRAS FUP').first().json || {};

const origemFup = clean(
  crmRoot.gatilho ||
  norm.gatilho ||
  norm.origem_fup ||
  ctx.crm_snapshot?.gatilho ||
  ''
);

const triggerEvent = clean(
  crmRoot.trigger_event ||
  norm.trigger_event ||
  norm.event ||
  ''
);

const ehAutomatico =
  origemFup.includes('FUP_AUTOMATICO') ||
  origemFup.includes('automatico') ||
  triggerEvent.includes('cron') ||
  norm.origem_fup === 'automatico_cron_mysql';

const nomeFluxo = ehAutomatico
  ? 'FUP_AUTOMATICO_BRUNA'
  : 'FUP_MANUAL_BRUNA';

const eventoChatwoot = ehAutomatico
  ? 'followup_automatico'
  : 'followup_manual';

const origemRegistroHistorico = ehAutomatico
  ? 'n8n_fup_automatico'
  : 'n8n_fup';

const tituloNota = ehAutomatico
  ? '[FUP BRUNA AUTOMÁTICO]'
  : '[FUP BRUNA MANUAL]';

function clean(value) {
  if (value === undefined || value === null) return '';
  return String(value).trim();
}

const textoResposta = clean(fup.mensagem_fup);
const podeEnviar = !!fup.pode_enviar && !!textoResposta;

const phone = clean(
  crmLead.phone ||
  memory.phone ||
  norm.phone ||
  crm.resumo_lead?.tutor_telefone ||
  ''
);

const accountId = Number(
  crmChatwoot.account_id ||
  memory.account_id_chatwoot ||
  norm.account_id ||
  0
);

const contactId = Number(
  crmChatwoot.contact_id ||
  memory.contact_id_chatwoot ||
  norm.contact_id ||
  0
);

const conversationId = Number(
  crmChatwoot.conversation_id ||
  memory.conversation_id_chatwoot ||
  norm.conversation_id ||
  0
);

const inboxId = Number(
  crmChatwoot.inbox_id ||
  norm.inbox_id ||
  memory.inbox_id ||
  0
);

const labelsAtuais = Array.isArray(crmChatwoot.labels)
  ? crmChatwoot.labels.map(x => clean(x)).filter(Boolean)
  : Array.isArray(norm.labels)
    ? norm.labels.map(x => clean(x)).filter(Boolean)
    : [];

const tagsAdd = Array.isArray(fup.tags_add)
  ? fup.tags_add.map(x => clean(x)).filter(Boolean)
  : [];

const tagsRemove = Array.isArray(fup.tags_remove)
  ? fup.tags_remove.map(x => clean(x)).filter(Boolean)
  : [];

const labelsFinais = [...new Set([
  ...labelsAtuais.filter(x => !tagsRemove.includes(x)),
  ...tagsAdd
])];

const resumoLead =
  ctx.resumo_lead_atual
  || crm.resumo_lead
  || memory.resumo_lead_json
  || {};

const resumoInternoRepasse =
  ctx.resumo_interno_repasse
  || crm.resumo_interno_repasse
  || memory.resumo_interno_repasse_json
  || {};

const tutorNome =
  resumoLead.tutor_nome
  || crmLead.sender_name
  || norm.lead_name
  || memory.nome_tutor
  || '';

const chatHistoryUuid =
  memory.chat_history_uuid
  || crmChatwoot.chat_history_uuid
  || norm.chat_history_uuid
  || `account:${accountId}-contact:${contactId}-conversation:${conversationId}-phone:${phone}`;

const statusNovo = fup.status_lead_novo || ctx.status_base || crm.status_lead || 'QUALIFICANDO';
const intencaoNova = fup.ultima_intencao_nova || 'SUMIU';

const mensagemUltimaLead =
  memory.mensagem_ultima_lead ||
  crmMessage.current_lead_block_text ||
  crmMessage.content_raw ||
  '';

const dataUltimaMensagemLead =
  memory.data_ultima_mensagem_lead ||
  crmMessage.created_at ||
  '';

const notaPrivadaTexto = podeEnviar
  ? `${tituloNota}
Tipo: ${fup.tipo_followup || ''}
Resumo: ${fup.resumo_followup || ''}
Status novo: ${statusNovo}
Última intenção nova: ${intencaoNova}
Telefone: ${phone}
Mensagem:
${textoResposta}`
  : `[FUP BRUNA NÃO ENVIADO]
Resumo: ${fup.resumo_followup || 'Sem contexto suficiente para envio.'}
Status base: ${ctx.status_base || ''}
Última intenção base: ${ctx.ultima_intencao_base || ''}
Motivo: ${ctx.motivo_bloqueio || ''}
Telefone: ${phone}`;

return [
  {
    json: {
      message: {
        message_modality: 'text_only',
        has_text: !!textoResposta,
        has_attachment: false,
        private: false,
        type: 'outgoing',
        content: {
          historico: crmMessage.historico || 'historico',
          history_for_crm: crmMessage.history_for_crm || '',
          first_message_id: crmMessage.first_message_id || null,
          last_message_id: crmMessage.last_message_id || null
        },
        data_url: null,
        source_id: null,
        created_at: new Date().toISOString(),
        historico: crmMessage.historico || 'historico',
        history_for_crm: crmMessage.history_for_crm || '',
        clean_answer: textoResposta
      },

      lead: {
        sender_name: tutorNome,
        phone,
        entry_channel: crmLead.entry_channel || memory.origem_detalhada || norm.origem || 'followup_manual_bruna',
        anuncio: crmLead.anuncio || norm.anuncio || '',
        utms: crmLead.utms || {},
        sender_type: crmLead.sender_type || 'contact'
      },

      chatwoot: {
        chat_history_uuid: chatHistoryUuid,
        labels: labelsAtuais,
        system_event: 'FOLLOWUP_DISPARADO',
        account_id: accountId,
        contact_id: contactId,
        message_id: null,
        conversation_id: conversationId,
        event: eventoChatwoot,
        inbox_id: inboxId
      },

      inputs: {
        status_lead: statusNovo,
        ultima_intencao: intencaoNova,
        evento_sistema: 'FOLLOWUP_DISPARADO',
        mensagens_resposta: Array.isArray(fup.mensagens_resposta)
          ? fup.mensagens_resposta
          : [textoResposta].filter(Boolean),

        resumo_lead: resumoLead,

        proxima_acao: podeEnviar
          ? (ehAutomatico ? 'Follow-up automático enviado pela Bruna.' : 'Follow-up manual enviado pela Bruna.')
          : (ehAutomatico ? 'Follow-up automático não enviado.' : 'Follow-up manual não enviado.'),
        deve_repassar_humano: false,
        motivo_repasse: '',
        deve_enviar_guia: false,
        deve_solicitar_pagamento: false,
        deve_consultar_agenda: false,
        deve_criar_pre_reserva: false,
        deve_encerrar_conversa: false,

        mensagem_ultima_lead: mensagemUltimaLead,
        data_ultima_mensagem_lead: dataUltimaMensagemLead,
        mensagem_ultima_bruna: textoResposta,
        email: memory.email_tutor || '',

        interpreted_message: 'text_message',
        interpreted_modality: 'text_only',
        interpreted_status: 'ok',
        supported_input: true,

        is_first_turn: false,

        resumo_interno_repasse: resumoInternoRepasse,

        versao_regras_negocio: 'v1',
        versao_contrato_payload: 'v1'
      },

      resposta: {
        phone,
        chat_history_uuid: chatHistoryUuid,
        account_id_chatwoot: accountId,
        contact_id_chatwoot: contactId,
        conversation_id_chatwoot: conversationId,
        message_id: null,
        id_mensagem_enviada: null,

        pode_enviar: podeEnviar,
        texto_resposta: textoResposta,
        message_fup: textoResposta,

        status_lead_novo: statusNovo,
        ultima_intencao_nova: intencaoNova,
        evento_sistema_novo: 'FOLLOWUP_DISPARADO',

        tipo_followup: fup.tipo_followup || ctx.tipo_followup_sugerido || 'FUP_1_RETOMADA_LEVE',
        resumo_followup: fup.resumo_followup || '',
        contador_followup_atual: Number(fup.contador_followup_atual || ctx.contador_followup_atual || 0),

        tags_add: tagsAdd,
        tags_remove: tagsRemove,

        resumo_lead_json: resumoLead,

        payload_atual_json: {
          origem_fluxo: nomeFluxo,
          eh_automatico: ehAutomatico,
          trigger_event: triggerEvent,
          fup,
          contexto_fup: ctx,
          crm: crmRoot,
          memory,
          config_followup: cfg
        }
      },

      opcoes: {
        eh_fup: true,

        envia_chatwoot: podeEnviar,
        atualizar_contact_summary: podeEnviar,
        gravar_memoria: podeEnviar,
        gravar_historico: podeEnviar,
        atualiza_labels: podeEnviar,
        adicionar_nota_privada: true,

        pula_verificao_ultima_mensagem: true,

        tipo_registro_historico: 'followup_bruna',
        origem_registro_historico: origemRegistroHistorico,

        labels_new: podeEnviar ? labelsFinais : labelsAtuais,

        nota_privada_texto: notaPrivadaTexto
      }
    }
  }
];

const maxFollowups = 5;

const bloquearAposLimite = true;

const tipos = [
  {
    numero: 1,
    tipo: 'FUP_1_RETOMADA_LEVE',
    tag: '11-fup-bruna-1',
    estrategia_padrao: 'RETOMADA_LEVE',
    objetivo_padrao: 'retomar a conversa com baixa fricção',
    tom_padrao: 'leve, humano e direto'
  },
  {
    numero: 2,
    tipo: 'FUP_2_DESTRAVA_OBJETIVO',
    tag: '11-fup-bruna-2',
    estrategia_padrao: 'DESTRAVAR_DECISAO',
    objetivo_padrao: 'entender a trava real do lead',
    tom_padrao: 'consultivo e sem pressão'
  },
  {
    numero: 3,
    tipo: 'FUP_3_REFORCO_VALOR',
    tag: '11-fup-bruna-3',
    estrategia_padrao: 'REFORCAR_VALOR',
    objetivo_padrao: 'reforçar o valor do processo sem parecer cobrança',
    tom_padrao: 'educativo e objetivo'
  },
  {
    numero: 4,
    tipo: 'FUP_4_DECISAO_FINAL',
    tag: '11-fup-bruna-4',
    estrategia_padrao: 'PEDIR_DECISAO',
    objetivo_padrao: 'pedir uma resposta simples para seguir ou pausar',
    tom_padrao: 'direto, leve e respeitoso'
  },
  {
    numero: 5,
    tipo: 'FUP_5_FECHAMENTO_ELEGANTE',
    tag: '11-fup-bruna-5',
    estrategia_padrao: 'FECHAMENTO_ELEGANTE',
    objetivo_padrao: 'encerrar sem insistência e deixar porta aberta',
    tom_padrao: 'elegante, breve e sem pressão'
  }
];

const tagsFup = tipos.map(t => t.tag);

return [
  {
    json: {
      max_followups: maxFollowups,
      bloquear_apos_limite: bloquearAposLimite,
      tipos_followup: tipos,
      tags_followup: tagsFup,
      tag_bloqueio: 'fup-bruna-bloqueado'
    }
  }
];
